#!/bin/bash
# Script para ver logs en tiempo real desde SSH en Render
# Ejecuta este script desde tu sesión SSH

echo "🔍 ========================================"
echo "🔍 VER LOGS EN TIEMPO REAL - DIAGNÓSTICO"
echo "🔍 ========================================"
echo ""

# Encontrar el directorio del proyecto
if [ -f "/opt/render/project/src/manage.py" ]; then
    PROJECT_DIR="/opt/render/project/src"
elif [ -f "./manage.py" ]; then
    PROJECT_DIR="."
else
    PROJECT_DIR=$(find /opt -name "manage.py" -type f 2>/dev/null | head -1 | xargs dirname)
fi

if [ -z "$PROJECT_DIR" ]; then
    echo "❌ No se encontró el proyecto Django"
    exit 1
fi

cd "$PROJECT_DIR"
echo "✅ Proyecto encontrado en: $PROJECT_DIR"
echo ""

